frappe.ui.form.on('Employee Advance', {
    custom_advance_type: function(frm) {
        if (!frm.doc.company) {
            frappe.msgprint(__('Please select a Company first.'));
            return;
        }

        frappe.db.get_doc('Company', frm.doc.company)
            .then(company => {
                 if (frm.doc.custom_advance_type === 'For Employee Advance') {
                    frm.set_value('advance_account', company.default_employee_advance_account);
                }
                else if (frm.doc.custom_advance_type === 'For Purchase') {
                    frm.set_value('advance_account', company.custom_default_account_for_purchaser_advance);
                } else if (frm.doc.custom_advance_type === 'For Petty Cash') {
                    frm.set_value('advance_account', company.custom_default_petty_cash_account);
                } else if (frm.doc.custom_advance_type === 'For Service') {
                    frm.set_value('advance_account', company.custom_default_account_for_service_advance);
                }
            })
            .catch(err => {
                console.error(err);
                frappe.msgprint(__('Failed to fetch company data'));
            });
    }
});

frappe.ui.form.on('Interview', {
    job_applicant: function(frm) {
        if (frm.doc.job_applicant) {
            frappe.call({
                method: "customized_forcommon.common_customization.doctype.applicant_test_result.applicant_test_result.get_applicant_test_scores",
                args: {
                    job_applicant: frm.doc.job_applicant
                },
                callback: function(r) {
                    if (r.message && r.message.length > 0) {
                        let result = r.message[0];
                        frm.set_value('custom_written_test_score', result.written_test_score);
                        frm.set_value('custom_practical_test_score', result.practical_test_score);
                    }
                }
            });
        }
    }
});

frappe.ui.form.on('Purchase Invoice', {
    refresh: function(frm) {
    // Setup query for custom_employee_advance field
    frm.set_query('custom_employee_advance', function() {
        return {
            filters: {
                docstatus: 1,         
                status: 'Paid'        
            }
        };
    });

    // Only calculate current balance if document is not submitted
    if (frm.doc.docstatus === 0) {  // docstatus 0 = Draft
        if (frm.doc.custom_advance_amount && frm.doc.grand_total) {
            let current_balance = frm.doc.custom_advance_amount - frm.doc.grand_total;
            frm.set_value("custom_current_balance", current_balance);
        }
    }
},

    on_submit: function(frm) {
        let advance_id = frm.doc.custom_employee_advance;
        let invoiced_amount = frm.doc.grand_total;
        let supplier = frm.doc.supplier;
        let company = frm.doc.company;

        if (!advance_id) {
            // frappe.msgprint(__('Please select an Employee Advance.'));
            return;
        }

        if (invoiced_amount <= 0 || !supplier) {
            // frappe.msgprint(__('Missing Employee Advance, Supplier, or Invoice Amount is Zero'));
            return;
        }

        // Fetch Employee Advance details first
        frappe.call({
            method: 'frappe.client.get',
            args: {
                doctype: 'Employee Advance',
                name: advance_id
            },
            callback: function(response) {
                if (!response.message) {
                    frappe.msgprint(__('Error fetching Employee Advance'));
                    return;
                }

                let advance = response.message;
                let employee = advance.employee;
                let advance_account = advance.advance_account;

                if (!advance_account) {
                    frappe.msgprint(__('No advance account found.'));
                    return;
                }

                // Fetch Company details next
                frappe.call({
                    method: 'frappe.client.get',
                    args: {
                        doctype: 'Company',
                        name: company
                    },
                    callback: function(company_response) {
                        if (!company_response.message) {
                            frappe.msgprint(__('Error fetching Company details'));
                            return;
                        }

                        let payable_account = company_response.message.default_payable_account;

                        if (!payable_account) {
                            frappe.msgprint(__('No Default Payable Account found in Company.'));
                            return;
                        }

                        // Insert First GL Entry (Debit - Supplier Payable)
                        frappe.call({
                            method: 'frappe.client.insert',
                            args: {
                                doc: {
                                    doctype: 'GL Entry',
                                    posting_date: frappe.datetime.nowdate(),
                                    company: company,
                                    voucher_type: 'Purchase Invoice',
                                    voucher_no: frm.doc.name,
                                    account: payable_account,
                                    party_type: 'Supplier',
                                    party: supplier,
                                    debit: invoiced_amount,
                                    credit: 0,
                                    against: advance_account,
                                    remarks: `Paying Supplier ${supplier} from Employee Advance`
                                }
                            },
                            callback: function(gl_response) {
                                if (!gl_response.message) {
                                    frappe.msgprint(__('Error Creating First GL Entry'));
                                    return;
                                }

                                // Insert Second GL Entry (Credit - Employee Advance)
                                frappe.call({
                                    method: 'frappe.client.insert',
                                    args: {
                                        doc: {
                                            doctype: 'GL Entry',
                                            posting_date: frappe.datetime.nowdate(),
                                            company: company,
                                            voucher_type: 'Purchase Invoice',
                                            voucher_no: frm.doc.name,
                                            account: advance_account,
                                            party_type: 'Employee',
                                            party: employee,
                                            debit: 0,
                                            credit: invoiced_amount,
                                            against: payable_account,
                                            remarks: `Clearing Employee Advance for ${employee}`
                                        }
                                    },
                                    callback: function(gl_response2) {
                                        if (!gl_response2.message) {
                                            frappe.msgprint(__('Error Creating Second GL Entry'));
                                            return;
                                        }

                                        // Finally, update Purchase Invoice status to "Paid"
                                        frappe.call({
                                            method: 'customized_forcommon.api.update_invoice_status',
                                            args: {
                                                docname: frm.doc.name,
                                                new_status: 'Paid'
                                            },
                                            callback: function(status_response) {
                                                if (status_response.message === 'success') {
                                                    // frappe.msgprint(__('Status Updated to Paid'));
                                                    frm.reload_doc();
                                                } else {
                                                    let error_message = status_response.error || 'Unknown error';
                                                    frappe.msgprint(__('Error updating status: ' + error_message));
                                                }
                                            }
                                        });

                                    }
                                });

                            }
                        });

                    }
                });
            }
        });
    }
});

frappe.ui.form.on('BOM Item', {
    custom_density: function (frm, cdt, cdn) {
        set_density_value(cdt, cdn);
        calculate_quantity(cdt, cdn);
    },
    custom_shape: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_length: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_width: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_height: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_diameter: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_outer_diameter: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_inner_diameter: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_number_of_sides: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_density_value: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    }
});


// Set density value based on selected material
function set_density_value(cdt, cdn) {
    let row = locals[cdt][cdn];
    const density_values = {
        "Aluminum": 2.70,
        "Brass": 8.50,
        "Bronze": 8.80,
        "Copper": 8.96,
        "Gold": 19.32,
        "Iron": 7.87,
        "Lead": 11.34,
        "Nickel": 8.90,
        "Platinum": 21.45,
        "Silver": 10.49,
        "Stainless Steel": 8.00,
        "Steel (Carbon)": 7.85,
        "Titanium": 4.51,
        "Zinc": 7.14
    };

    if (row.custom_density in density_values) {
        frappe.model.set_value(cdt, cdn, 'custom_density_value', density_values[row.custom_density]);
    }
}

// Calculate quantity based on shape and dimensions
function calculate_quantity(cdt, cdn) {
    let row = locals[cdt][cdn];

    let qty = 1;
    let density = parseFloat(row.custom_density_value || 0); // in kg/m³
    if (!density || !row.custom_shape) return;

    // Dimensions in mm, convert to meters
    let length = parseFloat(row.custom_length || 0) / 1000;
    let width = parseFloat(row.custom_width || 0) / 1000;
    let height = parseFloat(row.custom_height || 0) / 1000;

    if (row.custom_shape === "Rectangle") {
        let volume_m3 = length * width * height;
        qty = volume_m3 * density;
    }
    else if (row.custom_shape === "Circular") {
        let diameter = parseFloat(row.custom_diameter || 0) / 1000;
        let radius = diameter / 2;
        let volume_m3 = Math.PI * Math.pow(radius, 2) * length;
        qty = volume_m3 * density;
    }
    else if (row.custom_shape === "Tube") {
        let outer_d = parseFloat(row.custom_outer_diameter || 0) / 1000;
        let inner_d = parseFloat(row.custom_inner_diameter || 0) / 1000;
        let volume_m3 = (Math.PI / 4) * (Math.pow(outer_d, 2) - Math.pow(inner_d, 2)) * length;
        qty = volume_m3 * density;
    }
    else if (row.custom_shape === "Polygon") {
        let n_sides = parseInt(row.custom_number_of_sides || 0);
        let side_length = parseFloat(row.custom_width || 0) / 1000;
        let area = (n_sides * Math.pow(side_length, 2)) / (4 * Math.tan(Math.PI / n_sides));
        let volume_m3 = area * length;
        qty = volume_m3 * density;
    }

    frappe.model.set_value(cdt, cdn, 'qty', Math.floor(qty));
}



