frappe.ui.form.on('Quality Inspection', {
    reference_name(frm) {
        fetch_custom_quantity(frm);
    },
    item_code(frm) {
        fetch_custom_quantity(frm);
    },
    reference_type(frm) {
        fetch_custom_quantity(frm);
    }
});

function fetch_custom_quantity(frm) {
    const ref_type = frm.doc.reference_type;
    const ref_name = frm.doc.reference_name;
    const item = frm.doc.item_code;

    const supported_types = [
        "Purchase Receipt",
        "Purchase Invoice",
        "Delivery Note",
        "Sales Invoice",
        "Stock Entry",
        "Job Card"
    ];

    if (supported_types.includes(ref_type) && ref_name && (ref_type === "Job Card" || item)) {
        frappe.call({
            method: "customized_forcommon.api.get_reference_item_qty",
            args: {
                reference_type: ref_type,
                reference_name: ref_name,
                item_code: item || ""
            },
            callback: function (r) {
                if (r.message !== undefined) {
                    frm.set_value("custom_quantity", r.message);
                } else {
                    frm.set_value("custom_quantity", null);
                }
            }
        });
    } else {
        frm.set_value("custom_quantity", null);
    }
}
